public void serialize(Object value, JsonGenerator gen, SerializerProvider provider) throws IOException { Object delegateValue = convertValue(value); if (delegateValue == null) { provider.defaultSerializeNull(gen); return; } if (_delegateSerializer == null) { provider.findValueSerializer(delegateValue.getClass(), null).serialize(delegateValue, gen, provider); } else { _delegateSerializer.serialize(delegateValue, gen, provider); } }